VALUES ('16ba1197-7677-48ed-95e0-512491d0fdc6', 'A linear function $f$ satisfies $f(3) = 0$ and $f(7) = 8$. What is the value of $f(-4)$?', NULL, NULL, '[{"id":"A","text":"$-14$","is_correct":true,"explanation":"Slope $m = 2$. Then $f(-4) = -14$."},{"id":"B","text":"$-12$","is_correct":false,"explanation":"Adds 2 to the correct value."},{"id":"C","text":"$2$","is_correct":false,"explanation":"That is the slope, not $f(-4)$."},{"id":"D","text":"$-18$","is_correct":false,"explanation":"Subtracts 4 from the correct value."}]'::jsonb, 'A', 'Slope $m = 2$. Point-slope: $f(-4) = 2(-4-3)+(0) = -14$.', NULL, 'Algebra', 'Linear functions', 'math', 'algebra', 'LIF', 'LIF', 'easy', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
