VALUES ('cd481f10-9b1e-4f11-b8c5-1a1bf2c51665', 'In a mixture, the ratio of ingredient A to ingredient B is $3:4$. If the mixture contains 10 units total, how many units are ingredient A?', NULL, NULL, '[{"id":"A","text":"$2$","is_correct":false,"explanation":"Too small; compute $\\frac{3}{7} \\times 10$."},{"id":"B","text":"$4$","is_correct":true,"explanation":"$\\frac{3}{7} \\times 10 = 4$."},{"id":"C","text":"$7$","is_correct":false,"explanation":"Too large."},{"id":"D","text":"$10$","is_correct":false,"explanation":"That is the total, not ingredient A."}]'::jsonb, 'B', 'A''s share: $\frac{3}{7} \times 10 = 4$ units.', NULL, 'Problem-Solving and Data Analysis', 'Ratios, rates, and proportions', 'math', 'psda', 'RAT', 'RAT', 'medium', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
