VALUES ('320b285f-1920-433f-97b0-9106b166c966', 'What is the slope of the line?', 'A line passes through points $(1, 3)$ and $(5, 11)$ in the $xy$-plane.', NULL, '[{"id":"A","text":"$1$","is_correct":false,"explanation":"Incorrect rise over run."},{"id":"B","text":"$2$","is_correct":true,"explanation":"Slope = $\\frac{11-3}{5-1} = 2$."},{"id":"C","text":"$3$","is_correct":false,"explanation":"Adds 1 to the slope."},{"id":"D","text":"$11$","is_correct":false,"explanation":"That is a $y$-coordinate, not slope."}]'::jsonb, 'B', 'Slope = $\frac{8}{4} = 2$.', NULL, 'Problem-Solving and Data Analysis', 'Two-variable data', 'math', 'psda', 'TVA', 'TVA', 'hard', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
