VALUES ('c8c2a343-d2de-4070-8e8b-64c3e10a4064', 'What is the circumference of the circle? (Use $\pi \approx 3.14$.)', 'A circle has center $O$ and radius 4.', NULL, '[{"id":"A","text":"$50.24$","is_correct":false,"explanation":"That is an area expression $\\pi r^2$, not circumference."},{"id":"B","text":"$25.12$","is_correct":true,"explanation":"Circumference $C = 2\\pi r \\approx 2(3.14)(4) = 25.12$."},{"id":"C","text":"$8.00$","is_correct":false,"explanation":"That is the diameter, not circumference."},{"id":"D","text":"$12.56$","is_correct":false,"explanation":"That is $\\pi r$, not $2\\pi r$."}]'::jsonb, 'B', '$C = 2\pi r \approx 2(3.14)(4) = 25.12$.', NULL, 'Geometry and Trigonometry', 'Circles', 'math', 'geometry', 'CIR', 'CIR', 'easy', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
